// BatchDashboard.js
import React from 'react';

const BatchDashboard = ({ dashboardData }) => {
  if (!dashboardData || !dashboardData.fullData) {
    return (
      <div className="dashboard-container">
        <div className="no-data-message">
          <h2>No Batch Analysis Data Available</h2>
          <p>Please run a batch analysis first to see the results.</p>
        </div>
      </div>
    );
  }

  const { batchResult, timestamp, fullData } = dashboardData;
  const { summary, business_impact } = fullData;

  // Calculate additional metrics
  const highRiskCount = summary.risk_distribution['P1: High Risk (>70%)'] || 0;
  const mediumRiskCount = summary.risk_distribution['P2: Moderate Risk (31-70%)'] || 0;
  const lowRiskCount = summary.risk_distribution['P3: Low Risk (<=30%)'] || 0;
  const totalCustomers = summary.total_customers_processed;
  const retentionOpportunity = totalCustomers - highRiskCount;

  const downloadFullReport = () => {
    const report = `
BATCH CHURN ANALYSIS REPORT
===========================
Generated: ${timestamp}

EXECUTIVE SUMMARY
-----------------
Total Customers Processed: ${totalCustomers}
High-Risk Customers: ${highRiskCount} (${((highRiskCount/totalCustomers)*100).toFixed(1)}%)
Overall Churn Rate: ${summary.overall_churn_rate.toFixed(1)}%

RISK DISTRIBUTION
-----------------
🔴 High Risk (>70%): ${highRiskCount} customers
🟡 Moderate Risk (31-70%): ${mediumRiskCount} customers  
🟢 Low Risk (<=30%): ${lowRiskCount} customers

BUSINESS IMPACT
---------------
Potential Revenue Loss: ₹${business_impact?.total_potential_loss?.toLocaleString() || 'N/A'}
Recommended Retention Budget: ₹${business_impact?.retention_budget_recommended?.toLocaleString() || 'N/A'}
ROI on Retention: ${business_impact?.roi_retention?.toFixed(1) || 'N/A'}x

ACTION PLAN
-----------
🚨 Immediate Actions for High-Risk Customers:
• Executive-level outreach within 24 hours
• Premium incentives and personalized offers
• Root cause analysis of recent interactions

⚠️ Proactive Measures for Medium-Risk:
• Targeted campaigns within 7 days  
• Satisfaction surveys and feedback collection
• Loyalty program enhancements

✅ Retention Strengthening for Low-Risk:
• Advocacy program enrollment
• Cross-selling opportunities
• Regular value communication

Generated by ChurnGuard Analytics
${timestamp}
    `;

    const blob = new Blob([report], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `churn_analysis_report_${new Date().toISOString().split('T')[0]}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const copyChurnList = () => {
    const churnList = fullData.sample_predictions
      ?.filter(customer => customer.Risk_Level === 'P1: High Risk (>70%)')
      .map(customer => `${customer.CustomerID} - ${(customer.Churn_Probability * 100).toFixed(1)}%`)
      .join('\n') || 'No high-risk customers found';

    navigator.clipboard.writeText(churnList).then(() => {
      alert('High-risk customer list copied to clipboard!');
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="dashboard-container">
      <div className="view-title-section">
        <h2 className="view-title">
          <span className="view-icon">📊</span>
          Batch Processing Results Dashboard
        </h2>
        <p className="view-subtitle">
          Analysis completed on {timestamp}
        </p>
      </div>

      <div className="dashboard-content">
        {/* Key Metrics Cards */}
        <div className="stats-grid">
          <div className="stat-card primary">
            <div className="stat-card-icon">📄</div>
            <div className="stat-card-content">
              <h3>Total Records</h3>
              <div className="stat-card-value">{totalCustomers.toLocaleString()}</div>
            </div>
          </div>
          
          <div className="stat-card danger">
            <div className="stat-card-icon">⚠️</div>
            <div className="stat-card-content">
              <h3>Churn Count</h3>
              <div className="stat-card-value">{highRiskCount}</div>
            </div>
          </div>
          
          <div className="stat-card warning">
            <div className="stat-card-icon">📊</div>
            <div className="stat-card-content">
              <h3>Churn Rate</h3>
              <div className="stat-card-value">{summary.overall_churn_rate.toFixed(1)}%</div>
            </div>
          </div>
        </div>

        {/* Analysis Summary */}
        <div className="dashboard-section">
          <h3>Analysis Summary</h3>
          <div className="summary-cards">
            <div className="summary-card danger">
              <h4>High-Risk Customers</h4>
              <p>{highRiskCount} customers need immediate attention</p>
              <div className="risk-breakdown">
                <span className="risk-item">Probability: {(business_impact?.segment_breakdown?.high_risk?.avg_probability * 100)?.toFixed(1) || 'N/A'}%</span>
                <span className="risk-item">Avg Tenure: {business_impact?.segment_breakdown?.high_risk?.avg_tenure?.toFixed(1) || 'N/A'} months</span>
              </div>
            </div>
            <div className="summary-card success">
              <h4>Retention Opportunity</h4>
              <p>{retentionOpportunity} customers are stable</p>
              <div className="opportunity-breakdown">
                <span className="opportunity-item">Medium Risk: {mediumRiskCount}</span>
                <span className="opportunity-item">Low Risk: {lowRiskCount}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Business Impact */}
        {business_impact && (
          <div className="dashboard-section">
            <h3>Business Impact Analysis</h3>
            <div className="business-impact-grid">
              <div className="impact-card">
                <h4>Potential Revenue Loss</h4>
                <div className="impact-value">₹{business_impact.total_potential_loss?.toLocaleString() || 'N/A'}</div>
                <p>Estimated value at risk</p>
              </div>
              <div className="impact-card">
                <h4>Retention Budget</h4>
                <div className="impact-value">₹{business_impact.retention_budget_recommended?.toLocaleString() || 'N/A'}</div>
                <p>Recommended investment</p>
              </div>
              <div className="impact-card">
                <h4>ROI Potential</h4>
                <div className="impact-value">{business_impact.roi_retention?.toFixed(1) || 'N/A'}x</div>
                <p>Return on retention spend</p>
              </div>
            </div>
          </div>
        )}

        {/* Risk Distribution */}
        <div className="dashboard-section">
          <h3>Risk Distribution</h3>
          <div className="risk-distribution">
            <div className="risk-bar high-risk" style={{width: `${(highRiskCount/totalCustomers)*100}%`}}>
              <span>High Risk: {highRiskCount} ({(highRiskCount/totalCustomers*100).toFixed(1)}%)</span>
            </div>
            <div className="risk-bar medium-risk" style={{width: `${(mediumRiskCount/totalCustomers)*100}%`}}>
              <span>Medium Risk: {mediumRiskCount} ({(mediumRiskCount/totalCustomers*100).toFixed(1)}%)</span>
            </div>
            <div className="risk-bar low-risk" style={{width: `${(lowRiskCount/totalCustomers)*100}%`}}>
              <span>Low Risk: {lowRiskCount} ({(lowRiskCount/totalCustomers*100).toFixed(1)}%)</span>
            </div>
          </div>
        </div>

        {/* Export Results */}
        <div className="dashboard-section">
          <h3>Export Results</h3>
          <div className="export-actions">
            <button className="btn btn-primary" onClick={downloadFullReport}>
              📥 Download Full Report
            </button>
            <button className="btn btn-secondary" onClick={copyChurnList}>
              📋 Copy Churn List
            </button>
          </div>
        </div>

        {/* Data Source Info */}
        <div className="data-source-info">
          <p>
            <strong>Data Source:</strong> {fullData.data_source === 'simulated' ? 'Demo Data' : 'Uploaded File'} | 
            <strong> Processing Time:</strong> {fullData.processing_time_seconds || 'N/A'}s | 
            <strong> Model:</strong> {fullData.model_used === 'ml_model' ? 'Production ML' : 'Smart Logic'}
          </p>
        </div>
      </div>
    </div>
  );
};

export default BatchDashboard;
